sentences = []
while True:
    line = input()
    if line == 'END':
        break
    sentences.append(line)
word_count = {}

for sentence in sentences:
    words = sentence.lower().split()

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

print(word_count)
